<?php
declare(strict_types=1);

function ai_builder_page(string $title,string $kind,string $permission,array $questions):void{
    require_permission($permission);layout($title,function()use($title,$kind,$questions){?><div class="actions"><h1 style="margin:0"><?=e($title)?></h1><span class="spacer"></span></div><div class="card"><p>Describe the outcome you want. The AI uses your application branding and approved knowledge base, then creates an editable draft. Nothing is published automatically.</p><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><?php foreach($questions as $name=>$label):?><label><?=e($label)?><textarea name="<?=e($name)?>" <?=in_array($name,['goal','audience'],true)?'required':''?>></textarea></label><?php endforeach?><button>Generate editable draft</button></form></div><?php });
}
if($path==='/sites/ai/new'){
 require_permission('sites.edit');if($method==='POST'){verify_csrf();try{$brief='Create a responsive multi-page website. JSON schema: {"site_name":"...","slug":"...","pages":[{"name":"Home","slug":"","title":"SEO title","meta_description":"...","html":"semantic body HTML","css":"page CSS"}]}. Include 1-6 pages, a clear CTA, accessible headings, mobile-first CSS, and SEO copy. Audience: '.post('audience').' Goal: '.post('goal').' Requested pages: '.post('pages').' Tone: '.post('tone').' Extra instructions: '.post('details');$data=ai_builder_generate('website',$brief);$pages=array_slice(is_array($data['pages']??null)?$data['pages']:[],0,6);if(!$pages)throw new RuntimeException('No website pages were generated.');$slug=ai_builder_slug((string)($data['slug']??$data['site_name']??''),'site-'.bin2hex(random_bytes(3)));db()->beginTransaction();db()->prepare('INSERT INTO sites(name,slug,status,created_by,updated_by) VALUES(?,?,\'draft\',?,?)')->execute([mb_substr(trim((string)($data['site_name']??'AI website')),0,190),$slug,user()['id'],user()['id']]);$id=(int)db()->lastInsertId();$ins=db()->prepare('INSERT INTO site_pages(site_id,name,slug,title,meta_description,html,css,is_home,status,created_by,updated_by) VALUES(?,?,?,?,?,?,?,?,\'draft\',?,?)');foreach($pages as $i=>$p){$pageSlug=$i===0?'':ai_builder_slug((string)($p['slug']??$p['name']??''),'page-'.$i);$ins->execute([$id,mb_substr((string)($p['name']??'Page '.($i+1)),0,190),$pageSlug,mb_substr((string)($p['title']??$p['name']??''),0,255),mb_substr((string)($p['meta_description']??''),0,500),ai_builder_html((string)($p['html']??'')),ai_builder_css((string)($p['css']??'')),$i===0?1:0,user()['id'],user()['id']]);}audit('ai_create','site',$id,['name'=>$data['site_name']??'AI website','pages'=>count($pages)]);db()->commit();flash('success','AI website draft created. Review it in the visual editor before publishing.');redirect('/sites/'.$id);}catch(Throwable $e){if(db()->inTransaction())db()->rollBack();flash('error',$e->getMessage());}}
 ai_builder_page('AI Site Builder','website','sites.edit',['audience'=>'Who is the site for?','goal'=>'What should visitors understand or do?','pages'=>'Which pages should it include?','tone'=>'Desired voice and tone','details'=>'Products, offers, calls to action, and other instructions']);exit;
}
if($path==='/forms/ai/new'){
 require_permission('forms.edit');if($method==='POST'){verify_csrf();try{$brief='Create a lead-capture form. JSON schema: {"name":"...","slug":"...","thank_you_message":"...","submit_label":"...","fields":[{"key":"first_name","type":"text","label":"First name","placeholder":"","required":true,"crm_field":"first_name","options":[],"condition_key":"","condition_operator":"equals","condition_value":""}]}. Allowed types: text,email,tel,textarea,number,date,select,radio,checkbox. Allowed crm_field values: first_name,last_name,email,phone,company,job_title or null. Include only fields needed. Purpose: '.post('goal').' Audience: '.post('audience').' Requested information: '.post('fields').' Conditions/validation: '.post('rules').' Submit outcome: '.post('outcome');$data=ai_builder_generate('form',$brief);$fields=array_slice(is_array($data['fields']??null)?$data['fields']:[],0,30);if(!$fields)throw new RuntimeException('No form fields were generated.');$allowed=['text','email','tel','textarea','number','date','select','radio','checkbox'];$crmAllowed=['first_name','last_name','email','phone','company','job_title'];$slug=ai_builder_slug((string)($data['slug']??$data['name']??''),'form-'.bin2hex(random_bytes(3)));db()->beginTransaction();db()->prepare('INSERT INTO crm_forms(name,slug,visibility,thank_you_message,submit_label,active,created_by,updated_by) VALUES(?,?,\'public\',?,?,0,?,?)')->execute([mb_substr((string)($data['name']??'AI form'),0,190),$slug,mb_substr((string)($data['thank_you_message']??'Thank you for your submission.'),0,65000),mb_substr((string)($data['submit_label']??'Submit'),0,120),user()['id'],user()['id']]);$id=(int)db()->lastInsertId();$ins=db()->prepare('INSERT INTO crm_form_fields(form_id,field_key,field_type,label,placeholder,options_json,crm_field,required,position) VALUES(?,?,?,?,?,?,?,?,?)');$used=[];foreach($fields as $pos=>$f){$key=ai_builder_slug((string)($f['key']??$f['label']??''),'field-'.$pos);$key=str_replace('-','_',$key);if(isset($used[$key]))$key.='_'.$pos;$used[$key]=1;$type=in_array($f['type']??'', $allowed,true)?$f['type']:'text';$crm=in_array($f['crm_field']??'', $crmAllowed,true)?$f['crm_field']:null;$options=array_map(fn($v)=>mb_substr(trim((string)$v),0,120),(array)($f['options']??[]));$options=array_slice(array_values(array_filter($options)),0,50);$cfg=['options'=>$options,'condition_key'=>mb_substr((string)($f['condition_key']??''),0,80),'condition_operator'=>in_array($f['condition_operator']??'', ['equals','not_equals','contains','not_empty'],true)?$f['condition_operator']:'equals','condition_value'=>mb_substr((string)($f['condition_value']??''),0,255),'tag_map'=>[]];$ins->execute([$id,$key,$type,mb_substr((string)($f['label']??$key),0,190),mb_substr((string)($f['placeholder']??''),0,255),json_encode($cfg),$crm,!empty($f['required'])?1:0,$pos*10]);}audit('ai_create','crm_form',$id,['name'=>$data['name']??'AI form','fields'=>count($fields)]);db()->commit();flash('success','AI form draft created and disabled. Review it before making it active.');redirect('/forms/'.$id.'/edit');}catch(Throwable $e){if(db()->inTransaction())db()->rollBack();flash('error',$e->getMessage());}}
 ai_builder_page('AI Form Builder','form','forms.edit',['audience'=>'Who will complete this form?','goal'=>'What is the purpose of the form?','fields'=>'What information should it collect?','rules'=>'Conditional behavior or validation requirements','outcome'=>'What should happen or be shown after submission?']);exit;
}
if($path==='/resources/ai/new'){
 require_permission('resources.edit');if($method==='POST'){verify_csrf();try{$resources=db()->query('SELECT id,title,description FROM resources WHERE active=1 ORDER BY title')->fetchAll();$brief='Create a gated resource page using only resource IDs from the available catalog. JSON schema: {"name":"...","slug":"...","headline":"...","description":"...","thank_you_message":"...","resource_ids":[1,2]}. Audience: '.post('audience').' Goal: '.post('goal').' Desired topics/resources: '.post('resources').' Voice and instructions: '.post('details');$data=ai_builder_generate('resource portal',$brief,$resources);$valid=array_map('intval',array_column($resources,'id'));$ids=array_values(array_unique(array_filter(array_map('intval',(array)($data['resource_ids']??[])),fn($id)=>in_array($id,$valid,true))));$slug=ai_builder_slug((string)($data['slug']??$data['name']??''),'resources-'.bin2hex(random_bytes(3)));db()->beginTransaction();db()->prepare('INSERT INTO resource_portals(name,slug,headline,description,thank_you_message,fixed_tag_ids,active,created_by,updated_by) VALUES(?,?,?,?,?,\'[]\',0,?,?)')->execute([mb_substr((string)($data['name']??'AI resource page'),0,190),$slug,mb_substr((string)($data['headline']??'Resources'),0,255),mb_substr((string)($data['description']??''),0,65000),mb_substr((string)($data['thank_you_message']??'Thank you. Your resources are ready.'),0,65000),user()['id'],user()['id']]);$id=(int)db()->lastInsertId();$ins=db()->prepare('INSERT INTO resource_portal_items(portal_id,resource_id,position) VALUES(?,?,?)');foreach($ids as $pos=>$rid)$ins->execute([$id,$rid,$pos*10]);audit('ai_create','resource_portal',$id,['name'=>$data['name']??'AI resource page','resources'=>count($ids)]);db()->commit();flash('success','AI resource page draft created. Review its resources and registration settings before publishing.');redirect('/resources/portals/'.$id.'/edit');}catch(Throwable $e){if(db()->inTransaction())db()->rollBack();flash('error',$e->getMessage());}}
 ai_builder_page('AI Resource Page Builder','resource portal','resources.edit',['audience'=>'Who should use this resource page?','goal'=>'What goal should the page support?','resources'=>'Which topics or resources should be emphasized?','details'=>'Voice, positioning, and other instructions']);exit;
}

